  "plan": "Create and run `/app/work/refined_extractor.py` to combine both OCR streams: parse 1fps move-count anchors, segment 5fps bottom OCR into typed command submits, apply OCR corrections, filter game-text fragments with a common-command whitelist and length limit, preserve repeats except consecutive duplicates, and align candidates to move-count intervals. It will write `/app/work/logs/refined_candidates.log` and print whether the count is exactly 262. Then inspect the log in chunks. This is intermediate validation; no final solution.txt will be written yet.",
  "commands": [
    {
      "keystrokes": "cat > /app/work/refined_extractor.py <<'PY'
import glob, os, re
from collections import defaultdict

ocr1=sorted(glob.glob('/app/work/ocr/frame_*.txt'), key=lambda p:int(os.path.basename(p).split('_')[1].split('.')[0]))
bottom5=sorted(glob.glob('/app/work/bottom5/frame_*.txt'), key=lambda p:int(os.path.basename(p).split('_')[1].split('.')[0]))

fixes={
    'gY':'y','Y':'y','G':'again','g':'again',
    'move,':'move rug','open tra':'open trap',
    'ulysse':'ulysses','ulyss':'ulysses',
    'pu,':'put','pu':'put',
    'Dopen':'open','dopen':'open',
    'elose':'close','ceage':'cage','eage':'cage','ca_':'cage','ca':'cage',
    'mirro':'mirror',
    'temp':'temple','tem':'temple','tem_':'temple',
    'rin':'ring','dro':'drop',
    'get all fr':'get all from cage','get all from _':'get all from cage','get all from ca_':'get all from cage',
    'get lamp,clove':'get lamp,clove,screwdriver','get lamp,clove,sc':'get lamp,clove,screwdriver','get lamp,clove,screw':'get lamp,clove,screwdriver',
    'put torch,scr':'put torch,screwdriver','put torch,screw':'put torch,screwdriver',
    'get huge, tor':'get huge,torch','get huge,torc':'get huge,torch','get nuge,torcn':'get huge,torch','get huge,tor':'get huge,torch',
    'get egg,sow':'get egg,sword,lamp','get egg, sword,1':'get egg,sword,lamp',
    'get head, jade,cup,egg,go':'get head,jade,cup,egg,golden',
    'get head, jade,cup,egg, golden':'get head,jade,cup,egg,golden',
    'get head, jade,cup,egg,gold':'get head,jade,cup,egg,golden',
    'get head, Jade ,cup,egg,goiden':'get head,jade,cup,egg,golden',
    'Wind ac':'wind canary','Wind canary':'wind canary','win':'wind canary','win_':'wind canary',
    '1li':'lid','1lid':'lid','Lid':'lid','lid':'lid',
    'wW':'w','e,':'e','d.':'d','ne.':'ne',
    'n.':'n',
    'case':'case',
    'put all':'put all in case',
}

common=set('n s e w u d ne nw se sw get take drop put open close move kill again ring read rub set lower raise wind pray dig board launch pump echo save drink wait look give show wave blow pour turn tie untie climb jump enter push pull fill y g'.split())

def fix_cmd(s):
    s=s.strip().rstrip('._').strip()
    s=re.sub(r'\s+',' ',s).strip()
    return fixes.get(s,s)

def clean_prompt(s):
    s=s.strip()
    if not s.startswith('>'):
        return ''
    s=s[1:].strip().rstrip('._').strip()
    s=re.sub(r'\s+',' ',s).strip()
    return fix_cmd(s)

def normalize_bottom(s):
    s=re.sub(r'[^A-Za-z0-9>, ._]',' ',s)
    s=re.sub(r'\s+',' ',s).strip()
    had_prompt=s.startswith('>')
    if had_prompt:
        s=s[1:].strip()
    s=s.rstrip('._').strip()
    s=fix_cmd(s)
    return s, had_prompt

# Parse 1fps OCR
frames=[]
for idx,p in enumerate(ocr1,1):
    txt=open(p,errors='ignore').read()
    m=re.search(r'Moves?:\s*(\d+)', txt)
    mv=int(m.group(1)) if m else None
    prompts=[]
    for l in txt.splitlines():
        c=clean_prompt(l)
        if c:
            prompts.append(c)
    frames.append({'idx':idx,'mv':mv,'prompts':prompts})

anchors=[(i,frames[i]['mv']) for i in range(len(frames)) if frames[i]['mv'] is not None]

def b5_to_1fps(i):
    return max(1, min(len(frames), (i+4)//5))

# Parse dense bottom5 and create submitted command segments
b5=[]
for idx,p in enumerate(bottom5,1):
    raw=open(p,errors='ignore').read().strip()
    norm,had=normalize_bottom(raw)
    b5.append({'idx':idx,'cmd':norm if norm else '', 'had_prompt':had})

def is_commandlike(c):
    if not c:
        return False
    if len(c)>45:
        return False
    if not re.search(r'[A-Za-z]', c):
        return False
    first=c.split()[0].lower().strip('.,') if c.split() else ''
    if first in common:
        return True
    if c.lower() in ['y','again','g']:
        return True
    # allow fixed multiword commands even if first token OCR-merged
    if c in fixes.values():
        return True
    return False

# Build segments only from contiguous non-empty bottom prompt lines
segments=[]
cur=None
for r in b5:
    c=r['cmd']
    i=r['idx']
    if c:
        if cur is None:
            cur=(i,c)
        elif c.startswith(cur[1]) or (len(cur[1])>=3 and c.startswith(cur[1][:-1])):
            cur=(i,c)
        elif cur[1].startswith(c) and len(cur[1])-len(c)<=3:
            pass
        else:
            segments.append(cur)
            cur=(i,c)
    else:
        if cur:
            segments.append(cur)
            cur=None
if cur:
    segments.append(cur)

# Filter game-text fragments
b5_cmds=[]
for i,c in segments:
    c=fix_cmd(c)
    if is_commandlike(c):
        b5_cmds.append((i,c))

# Deduplicate consecutive identical submits only
b5_ded=[]
for i,c in b5_cmds:
    if b5_ded and b5_ded[-1][1] == c:
        continue
    b5_ded.append((i,c))

# Align to move-count intervals
final=[]
if anchors:
    prev_i, prev_mv = 0, 0
    for end_i, end_mv in anchors:
        if end_mv <= prev_mv:
            continue
        delta = end_mv - prev_mv
        # dense bottom commands whose 1fps frame is between prev_i+1 and end_i inclusive
        interval=[(b5_to_1fps(i), c) for i,c in b5_ded if prev_i < b5_to_1fps(i) <= end_i]
        # If no dense interval commands, fallback to 1fps prompt history last commands
        if not interval:
            for j in range(max(0,prev_i), end_i+1):
                if frames[j]['prompts']:
                    interval.append((frames[j]['idx'], frames[j]['prompts'][-1]))
        # Remove pure prefixes of later commands; keep identical/repeats separated by other commands.
        kept=[]
        for n,(j,c) in enumerate(interval):
            is_prefix=False
            for jj,cc in interval[n+1:]:
                if cc.startswith(c) and len(cc) > len(c):
                    is_prefix=True
                    break
            if not is_prefix:
                kept.append((j,c))
        chosen=kept[-delta:] if delta <= len(kept) else kept
        final.extend(chosen)
        prev_i, prev_mv = end_i, end_mv
else:
    final=[(b5_to_1fps(i), c) for i,c in b5_ded]

# Deduplicate consecutive identical only after alignment
ded_final=[]
for j,c in final:
    if ded_final and ded_final[-1][1]==c:
        continue
    ded_final.append((j,c))

with open('/app/work/logs/refined_candidates.log','w') as f:
    for n,(j,c) in enumerate(ded_final,1):
        f.write(f'{n:03d} f{j:03d} {c}\n')

print('refined_count', len(ded_final))
print('expected', 262)
print('match', len(ded_final)==262)
print('first30', ded_final[:30])
print('last30', ded_final[-30:])
